def verify(answer):
    from sympy import isprime

    try:
        candidate = int(str(answer).strip())
    except Exception:
        return False

    # Check if the candidate is prime
    if not isprime(candidate):
        return False

    # Check if the candidate gives a remainder of 2 when divided by 25
    if candidate % 25 != 2:
        return False

    # Check if it is the least such prime greater than 25
    for num in range(26, candidate):
        if isprime(num) and num % 25 == 2:
            return False

    return True

